    def search_entities(data, source='Unknown'):
        if isinstance(data, dict):
            source = data.get('source', source)
            for k, v in data.items():
                if k.lower() in ORG_KEYWORDS or (isinstance(v, str) and any(org in v.lower() for org in ORG_KEYWORDS)):
                    orgs.add((str(v), source))
                if isinstance(v, str):
                    for d in re.findall(DATE_REGEX, v):
                        dates.add((d, source))
                    for s in re.findall(SPEC_REGEX, v):
                        specs.add((s, source))
                search_entities(v, source)
        elif isinstance(data, list):
            for item in data:
                search_entities(item, source)

    search_entities(doc)
    return {
        'Organizations': list(orgs),
        'Dates': list(dates),
        'Specs': list(specs)
    }

