    # Remove punctuation and lowercase
    text = text.translate(str.maketrans('', '', string.punctuation)).lower()
    words = [w for w in text.split() if w not in STOPWORDS and w.isalpha()]
    count = Counter(words)
    # Most common nouns/phrases as themes
    themes = [w for w, _ in count.most_common(5)]
    return themes

