            'Organizations': entity_map.get('Organizations', []),
            'Dates': entity_map.get('Dates', []),
            'Specs': entity_map.get('Specs', []),
            'Themes': themes,
            'Missing Fields': gaps
        }])
        return df
    except Exception as e:
        print(f'Error in analysis: {e}')
        return pd.DataFrame()

