        'destination': 'Berlin',
        'luggage_allowance': 'up to 23kg',
        'cost': '',
        'airline': 'Omega Airlines',
        'travel_time': None
    }
    df_report = analyze_document(doc)
    print(df_report.to_markdown(index=False))
